INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**צנרת ביוב – קוטר לא מספיק** — צנרת ביוב בקוטר קטן מהנדרש לכמות הכלים הסניטריים המחוברים אליה, גורם לחסימות תכופות.. המלצה: להחליף את קטע הצנרת בקוטר מתאים בהתאם לתקן ולכמות הכלים הסניטריים המחוברים.. עלות משוערת: ₪500-₪2500 (למ"א)', '**צנרת ביוב – קוטר לא מספיק** — צנרת ביוב בקוטר קטן מהנדרש לכמות הכלים הסניטריים המחוברים אליה, גורם לחסימות תכופות.. המלצה: להחליף את קטע הצנרת בקוטר מתאים בהתאם לתקן ולכמות הכלים הסניטריים המחוברים.. עלות משוערת: ₪500-₪2500 (למ"א)', 'ת"י 1205 חלק 2 — קוטר צנרת ביוב מינימלי: אסלה – 100 מ"מ, כיור – 40 מ"מ, מקלחת – 50 מ"מ, קו ראשי – 100 מ"מ.', 'ת"י 1205 חלק 2 — קוטר צנרת ביוב מינימלי: אסלה – 100 מ"מ, כיור – 40 מ"מ, מקלחת – 50 מ"מ, קו ראשי – 100 מ"מ.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**אוורור מערכת ביוב חסר או לקוי** — מערכת הביוב ללא אוורור תקין (vent pipe), גורם לשאיבת מחסום המים מהסיפונים, רעשי גרגור, וחדירת ריחות ביוב.. המלצה: להתקין צנרת אוורור בקוטר מתאים, המתחברת לעמוד הביוב ועולה לגג המבנה, או להתקין שסתום אוורור (Air Admittance Valve).. עלות משוערת: ₪500-₪2000 (ליחידה)', '**אוורור מערכת ביוב חסר או לקוי** — מערכת הביוב ללא אוורור תקין (vent pipe), גורם לשאיבת מחסום המים מהסיפונים, רעשי גרגור, וחדירת ריחות ביוב.. המלצה: להתקין צנרת אוורור בקוטר מתאים, המתחברת לעמוד הביוב ועולה לגג המבנה, או להתקין שסתום אוורור (Air Admittance Valve).. עלות משוערת: ₪500-₪2000 (ליחידה)', 'ת"י 1205 חלק 2 — כל עמוד ביוב אנכי יאוורר לגג המבנה. צנרת האוורור לא תהיה קטנה מ-50 מ"מ ותגיע לפחות 50 ס"מ מעל הגג.', 'ת"י 1205 חלק 2 — כל עמוד ביוב אנכי יאוורר לגג המבנה. צנרת האוורור לא תהיה קטנה מ-50 מ"מ ותגיע לפחות 50 ס"מ מעל הגג.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**שסתום אוורור (AAV) לא תקין** — שסתום אוורור (Air Admittance Valve) לא עובד, סתום, או מותקן במיקום שגוי, אינו מאפשר כניסת אוויר למערכת הביוב.. המלצה: להחליף את שסתום האוורור בשסתום חדש תקין, ולהתקין בגובה ובמיקום הנכונים.. עלות משוערת: ₪100-₪350 (ליחידה)', '**שסתום אוורור (AAV) לא תקין** — שסתום אוורור (Air Admittance Valve) לא עובד, סתום, או מותקן במיקום שגוי, אינו מאפשר כניסת אוויר למערכת הביוב.. המלצה: להחליף את שסתום האוורור בשסתום חדש תקין, ולהתקין בגובה ובמיקום הנכונים.. עלות משוערת: ₪100-₪350 (ליחידה)', 'ת"י 1205 חלק 2 — שסתום אוורור יותקן מעל לגובה הגלישה של הכלי הסניטרי הגבוה ביותר המחובר לקו, במקום מאוורר.', 'ת"י 1205 חלק 2 — שסתום אוורור יותקן מעל לגובה הגלישה של הכלי הסניטרי הגבוה ביותר המחובר לקו, במקום מאוורר.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**מכסה בור ביקורת ביוב – חסר או פגום** — מכסה בור ביקורת (שוחת ביוב) חסר, שבור, לא אטום, או לא מפולס עם הרצפה/קרקע.. המלצה: להחליף את המכסה הפגום במכסה חדש תקני, לוודא אטימות ופילוס.. עלות משוערת: ₪200-₪800 (ליחידה)', '**מכסה בור ביקורת ביוב – חסר או פגום** — מכסה בור ביקורת (שוחת ביוב) חסר, שבור, לא אטום, או לא מפולס עם הרצפה/קרקע.. המלצה: להחליף את המכסה הפגום במכסה חדש תקני, לוודא אטימות ופילוס.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 2 — בורות ביקורת יהיו עם מכסים אטומים, בחוזק מספיק, ונגישים לתחזוקה.', 'ת"י 1205 חלק 2 — בורות ביקורת יהיו עם מכסים אטומים, בחוזק מספיק, ונגישים לתחזוקה.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**גלישת מים מאמבטיה/מקלחת לחדרים סמוכים** — מים מחדר הרחצה/מקלחת חודרים לחדרים סמוכים בשל היעדר מפתן, איטום לקוי, או שיפוע שגוי.. המלצה: להתקין מפתן בכניסה לחדר הרטוב, לבדוק ולתקן איטום רצפה, ולוודא שיפוע נכון לכיוון הסיפון.. עלות משוערת: ₪500-₪2500 (ליחידה)', '**גלישת מים מאמבטיה/מקלחת לחדרים סמוכים** — מים מחדר הרחצה/מקלחת חודרים לחדרים סמוכים בשל היעדר מפתן, איטום לקוי, או שיפוע שגוי.. המלצה: להתקין מפתן בכניסה לחדר הרטוב, לבדוק ולתקן איטום רצפה, ולוודא שיפוע נכון לכיוון הסיפון.. עלות משוערת: ₪500-₪2500 (ליחידה)', 'ת"י 1205 חלק 2 — חדרים רטובים חייבים במפתן או הפרש גובה מול חדרים יבשים, ובאיטום רצפה תקני למניעת חדירת מים.', 'ת"י 1205 חלק 2 — חדרים רטובים חייבים במפתן או הפרש גובה מול חדרים יבשים, ובאיטום רצפה תקני למניעת חדירת מים.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**ניקוז מזגן – חיבור ישיר לביוב ללא סיפון** — ניקוז עיבוי מזגן מחובר ישירות לצנרת ביוב ללא סיפון, גורם לחדירת ריחות ביוב דרך היחידה הפנימית.. המלצה: להתקין סיפון ייעודי לצנרת ניקוז עיבוי המזגן, לפני החיבור למערכת הביוב.. עלות משוערת: ₪150-₪400 (ליחידה)', '**ניקוז מזגן – חיבור ישיר לביוב ללא סיפון** — ניקוז עיבוי מזגן מחובר ישירות לצנרת ביוב ללא סיפון, גורם לחדירת ריחות ביוב דרך היחידה הפנימית.. המלצה: להתקין סיפון ייעודי לצנרת ניקוז עיבוי המזגן, לפני החיבור למערכת הביוב.. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1205 חלק 2 — כל חיבור למערכת הביוב חייב לעבור דרך סיפון עם מחסום ריח.', 'ת"י 1205 חלק 2 — כל חיבור למערכת הביוב חייב לעבור דרך סיפון עם מחסום ריח.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**מרזב/צנרת ניקוז מרפסת – שיפוע לא תקין** — רצפת המרפסת ללא שיפוע מספיק לניקוז מי גשם, מים עומדים על המרפסת וחודרים לדירה.. המלצה: לבצע יציקת שיפוע מתקנת, להתקין ריצוף עם שיפוע תקני, ולוודא ניקוז תקין לנקודת היציאה.. עלות משוערת: ₪1500-₪4000 (ליחידה)', '**מרזב/צנרת ניקוז מרפסת – שיפוע לא תקין** — רצפת המרפסת ללא שיפוע מספיק לניקוז מי גשם, מים עומדים על המרפסת וחודרים לדירה.. המלצה: לבצע יציקת שיפוע מתקנת, להתקין ריצוף עם שיפוע תקני, ולוודא ניקוז תקין לנקודת היציאה.. עלות משוערת: ₪1500-₪4000 (ליחידה)', 'ת"י 1205 חלק 2 — מרפסות חשופות חייבות בשיפוע מינימלי של 1.5% לכיוון נקודת ניקוז, עם חיבור תקין למערכת ניקוז גשם.', 'ת"י 1205 חלק 2 — מרפסות חשופות חייבות בשיפוע מינימלי של 1.5% לכיוון נקודת ניקוז, עם חיבור תקין למערכת ניקוז גשם.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**משאבת ייחוץ (סמפ) – חסרה או לא תקינה** — בדירות קרקע או מרתפים – משאבת ייחוץ חסרה, לא מחוברת, או לא פועלת, סיכון להצפה.. המלצה: להתקין או לתקן משאבת ייחוץ עם שסתום חד-כיווני, לבדוק חיבור חשמל וצף הפעלה.. עלות משוערת: ₪1500-₪5000 (ליחידה)', '**משאבת ייחוץ (סמפ) – חסרה או לא תקינה** — בדירות קרקע או מרתפים – משאבת ייחוץ חסרה, לא מחוברת, או לא פועלת, סיכון להצפה.. המלצה: להתקין או לתקן משאבת ייחוץ עם שסתום חד-כיווני, לבדוק חיבור חשמל וצף הפעלה.. עלות משוערת: ₪1500-₪5000 (ליחידה)', 'ת"י 1205 חלק 2 — בכל מקום שבו נקודת הניקוז נמצאת מתחת לגובה הביוב העירוני, יש להתקין משאבת ייחוץ עם שסתום חד-כיווני.', 'ת"י 1205 חלק 2 — בכל מקום שבו נקודת הניקוז נמצאת מתחת לגובה הביוב העירוני, יש להתקין משאבת ייחוץ עם שסתום חד-כיווני.', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**ניקוז איטי במקלחת** — מים מתנקזים לאט במקלחת — עלול לנבוע מחוסר שיפוע או חסימה בצנרת.. המלצה: בדיקת שיפוע, פתיחת סתימה, תיקון שיפוע אם נדרש. עלות משוערת: ₪200-₪800 (ליחידה)', '**ניקוז איטי במקלחת** — מים מתנקזים לאט במקלחת — עלול לנבוע מחוסר שיפוע או חסימה בצנרת.. המלצה: בדיקת שיפוע, פתיחת סתימה, תיקון שיפוע אם נדרש. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 — ניקוז מקלחת חייב להתבצע תוך זמן סביר', 'ת"י 1205 — ניקוז מקלחת חייב להתבצע תוך זמן סביר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**חוסר שיפוע בניקוז מרפסת** — מרפסת ללא שיפוע מספיק לניקוז — מים נשארים על המשטח.. המלצה: תיקון שיפוע ריצוף לכיוון ניקוז. עלות משוערת: ₪150-₪500 (למ"ר)', '**חוסר שיפוע בניקוז מרפסת** — מרפסת ללא שיפוע מספיק לניקוז — מים נשארים על המשטח.. המלצה: תיקון שיפוע ריצוף לכיוון ניקוז. עלות משוערת: ₪150-₪500 (למ"ר)', 'ת"י 1515.3 — שיפוע מינימלי לניקוז: 1.5%', 'ת"י 1515.3 — שיפוע מינימלי לניקוז: 1.5%', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**התקנה לקויה של אינטרפוץ (מערבל מקלחת)** — אינטרפוץ מותקן שלא בגובה הנדרש, בולט מהקיר, לא מפולס, או שיש דליפה מסביבו. חיבורי המים חמים וקרים עשויים להיות מחוברים הפוך.. המלצה: לפרק את האינטרפוץ, לתקן את עמדת הצנרת בקיר, להתקין מחדש בגובה ובמיקום הנכונים, ולוודא חיבור תקין ללא דליפות.. עלות משוערת: ₪400-₪1500 (ליחידה)', '**התקנה לקויה של אינטרפוץ (מערבל מקלחת)** — אינטרפוץ מותקן שלא בגובה הנדרש, בולט מהקיר, לא מפולס, או שיש דליפה מסביבו. חיבורי המים חמים וקרים עשויים להיות מחוברים הפוך.. המלצה: לפרק את האינטרפוץ, לתקן את עמדת הצנרת בקיר, להתקין מחדש בגובה ובמיקום הנכונים, ולוודא חיבור תקין ללא דליפות.. עלות משוערת: ₪400-₪1500 (ליחידה)', 'ת"י 1205 חלק 2 — אינטרפוץ יותקן בגובה 100-110 ס"מ מרצפת המקלחת, מפולס, צמוד לקיר, כשהחיבור החם בצד שמאל (בהסתכלות חזיתית).', 'ת"י 1205 חלק 2 — אינטרפוץ יותקן בגובה 100-110 ס"מ מרצפת המקלחת, מפולס, צמוד לקיר, כשהחיבור החם בצד שמאל (בהסתכלות חזיתית).', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**חיבור מים חמים וקרים הפוך באינטרפוץ/מערבל** — חיבורי המים החמים והקרים מחוברים בצורה הפוכה – כיוון סיבוב הידית אינו תואם לטמפרטורת המים בפועל.. המלצה: להחליף את חיבורי הצנרת החמה והקרה כך שיתאימו לתקן ולסימון על הברז.. עלות משוערת: ₪200-₪800 (ליחידה)', '**חיבור מים חמים וקרים הפוך באינטרפוץ/מערבל** — חיבורי המים החמים והקרים מחוברים בצורה הפוכה – כיוון סיבוב הידית אינו תואם לטמפרטורת המים בפועל.. המלצה: להחליף את חיבורי הצנרת החמה והקרה כך שיתאימו לתקן ולסימון על הברז.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 2 — חיבור מים חמים בצד שמאל וקרים בצד ימין (בהסתכלות חזיתית). סיבוב הידית שמאלה = חם, ימינה = קר.', 'ת"י 1205 חלק 2 — חיבור מים חמים בצד שמאל וקרים בצד ימין (בהסתכלות חזיתית). סיבוב הידית שמאלה = חם, ימינה = קר.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**ברז מטבח/כיור רופף או לא יציב** — ברז הכיור במטבח או בחדר הרחצה רופף, נע ממקומו, או לא מהודק כראוי לכיור/משטח.. המלצה: להדק את אום החיזוק מתחת לכיור, להחליף אטם בסיס הברז במידת הצורך, ולוודא יציבות מלאה.. עלות משוערת: ₪100-₪350 (ליחידה)', '**ברז מטבח/כיור רופף או לא יציב** — ברז הכיור במטבח או בחדר הרחצה רופף, נע ממקומו, או לא מהודק כראוי לכיור/משטח.. המלצה: להדק את אום החיזוק מתחת לכיור, להחליף אטם בסיס הברז במידת הצורך, ולוודא יציבות מלאה.. עלות משוערת: ₪100-₪350 (ליחידה)', 'ת"י 1205 חלק 2 — כל כלי סניטרי וברז יותקנו באופן יציב וחזק, ללא תזוזה, בהתאם להוראות היצרן.', 'ת"י 1205 חלק 2 — כל כלי סניטרי וברז יותקנו באופן יציב וחזק, ללא תזוזה, בהתאם להוראות היצרן.', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**נזילה מברז – טפטוף מתמשך** — ברז מטפטף גם במצב סגור. בזבוז מים, רעש מטריד, ועלול לגרום לכתמי אבנית על הכיור.. המלצה: להחליף קרטוש (cartridge) של הברז, או את הברז כולו אם מדובר בדגם ישן או פגום.. עלות משוערת: ₪100-₪500 (ליחידה)', '**נזילה מברז – טפטוף מתמשך** — ברז מטפטף גם במצב סגור. בזבוז מים, רעש מטריד, ועלול לגרום לכתמי אבנית על הכיור.. המלצה: להחליף קרטוש (cartridge) של הברז, או את הברז כולו אם מדובר בדגם ישן או פגום.. עלות משוערת: ₪100-₪500 (ליחידה)', 'ת"י 1205 חלק 2 — ברזים חייבים להיות אטומים לחלוטין במצב סגור. אין לאפשר טפטוף או דליפה.', 'ת"י 1205 חלק 2 — ברזים חייבים להיות אטומים לחלוטין במצב סגור. אין לאפשר טפטוף או דליפה.', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**אסלה רופפת – אינה מקובעת לרצפה** — האסלה נעה ממקומה, לא מקובעת כראוי לרצפה או לקיר (אסלה תלויה). עלולה לגרום לדליפת מים מהחיבור לביוב.. המלצה: להדק את ברגי הקיבוע של האסלה לרצפה, להחליף אטם שעווה (wax ring) בחיבור לביוב, ולאטום בסיליקון.. עלות משוערת: ₪200-₪600 (ליחידה)', '**אסלה רופפת – אינה מקובעת לרצפה** — האסלה נעה ממקומה, לא מקובעת כראוי לרצפה או לקיר (אסלה תלויה). עלולה לגרום לדליפת מים מהחיבור לביוב.. המלצה: להדק את ברגי הקיבוע של האסלה לרצפה, להחליף אטם שעווה (wax ring) בחיבור לביוב, ולאטום בסיליקון.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1205 חלק 2 — כלים סניטריים יקובעו באופן יציב ובטוח, ללא תנועה, בהתאם להוראות היצרן ולסוג הקיבוע.', 'ת"י 1205 חלק 2 — כלים סניטריים יקובעו באופן יציב ובטוח, ללא תנועה, בהתאם להוראות היצרן ולסוג הקיבוע.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**ניקוז איטי באסלה – שטיפה לא מספקת** — האסלה אינה מתנקזת כראוי, השטיפה חלשה או חלקית, המים עולים ויורדים באיטיות.. המלצה: לבדוק חסימות בצנרת הביוב, לבדוק תקינות מנגנון ההדחה בניאגרה, לנקות או להחליף חלקים פנימיים.. עלות משוערת: ₪150-₪500 (ליחידה)', '**ניקוז איטי באסלה – שטיפה לא מספקת** — האסלה אינה מתנקזת כראוי, השטיפה חלשה או חלקית, המים עולים ויורדים באיטיות.. המלצה: לבדוק חסימות בצנרת הביוב, לבדוק תקינות מנגנון ההדחה בניאגרה, לנקות או להחליף חלקים פנימיים.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1205 חלק 2 — מנגנון ההדחה חייב לספק נפח מים מספיק לניקוי יעיל של האסלה בשטיפה אחת (6/3 ליטר במנגנון דו-כמותי).', 'ת"י 1205 חלק 2 — מנגנון ההדחה חייב לספק נפח מים מספיק לניקוי יעיל של האסלה בשטיפה אחת (6/3 ליטר במנגנון דו-כמותי).', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**נזילה מניאגרה (מיכל הדחה)** — נזילת מים מתמדת מהניאגרה לתוך האסלה (מים זורמים ללא הפסקה) או דליפה חיצונית מהמיכל.. המלצה: להחליף את מנגנון הניאגרה הפנימי (שסתום מצוף ושסתום פריקה), לבדוק אטימות חיבורי המים.. עלות משוערת: ₪150-₪450 (ליחידה)', '**נזילה מניאגרה (מיכל הדחה)** — נזילת מים מתמדת מהניאגרה לתוך האסלה (מים זורמים ללא הפסקה) או דליפה חיצונית מהמיכל.. המלצה: להחליף את מנגנון הניאגרה הפנימי (שסתום מצוף ושסתום פריקה), לבדוק אטימות חיבורי המים.. עלות משוערת: ₪150-₪450 (ליחידה)', 'ת"י 1205 חלק 2 — מנגנון ההדחה חייב להיות אטום ולעצור זרימת מים לאחר סיום מחזור ההדחה.', 'ת"י 1205 חלק 2 — מנגנון ההדחה חייב להיות אטום ולעצור זרימת מים לאחר סיום מחזור ההדחה.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**כיור/כיור רחצה סדוק או פגום** — סדק, שבר, או פגם בכיור המטבח או כיור חדר הרחצה. פגם אסתטי ופוטנציאל לדליפת מים.. המלצה: להחליף את הכיור הפגום בכיור חדש תקין ולחבר מחדש את הצנרת.. עלות משוערת: ₪500-₪2000 (ליחידה)', '**כיור/כיור רחצה סדוק או פגום** — סדק, שבר, או פגם בכיור המטבח או כיור חדר הרחצה. פגם אסתטי ופוטנציאל לדליפת מים.. המלצה: להחליף את הכיור הפגום בכיור חדש תקין ולחבר מחדש את הצנרת.. עלות משוערת: ₪500-₪2000 (ליחידה)', 'ת"י 1205 חלק 2 — כלים סניטריים יסופקו ויותקנו ללא פגמים, סדקים, שברים או פגיעה בציפוי.', 'ת"י 1205 חלק 2 — כלים סניטריים יסופקו ויותקנו ללא פגמים, סדקים, שברים או פגיעה בציפוי.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**אמבטיה – אטימה לקויה בחיבור לקיר** — אמבטיה שאינה אטומה כראוי בחיבור לקיר, מים חודרים מאחורי האמבטיה וגורמים לנזקי רטיבות.. המלצה: להסיר את האיטום הישן, לנקות ולייבש את המשטח, ולמרוח סיליקון סניטרי איכותי עמיד לעובש.. עלות משוערת: ₪150-₪400 (ליחידה)', '**אמבטיה – אטימה לקויה בחיבור לקיר** — אמבטיה שאינה אטומה כראוי בחיבור לקיר, מים חודרים מאחורי האמבטיה וגורמים לנזקי רטיבות.. המלצה: להסיר את האיטום הישן, לנקות ולייבש את המשטח, ולמרוח סיליקון סניטרי איכותי עמיד לעובש.. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1205 חלק 2 — חיבור האמבטיה לקיר חייב להיות אטום למים באמצעות חומר איטום גמיש (סיליקון סניטרי) למניעת חדירת מים.', 'ת"י 1205 חלק 2 — חיבור האמבטיה לקיר חייב להיות אטום למים באמצעות חומר איטום גמיש (סיליקון סניטרי) למניעת חדירת מים.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**מקלחון – נזילה מדלת/מחיצת זכוכית** — נזילת מים מדלת המקלחון או ממחיצת הזכוכית, גורמת להצפת מים מחוץ לתא המקלחת.. המלצה: להחליף רצועות איטום (seals) של דלת המקלחון, לכוונן את הדלת, או לתקן את פרופיל האלומיניום.. עלות משוערת: ₪200-₪800 (ליחידה)', '**מקלחון – נזילה מדלת/מחיצת זכוכית** — נזילת מים מדלת המקלחון או ממחיצת הזכוכית, גורמת להצפת מים מחוץ לתא המקלחת.. המלצה: להחליף רצועות איטום (seals) של דלת המקלחון, לכוונן את הדלת, או לתקן את פרופיל האלומיניום.. עלות משוערת: ₪200-₪800 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**ראש מקלחת (דוש) – לחץ נמוך או סתימה** — ראש המקלחת מפזר מים בצורה לא אחידה, זרימה חלשה, או חלק מהנחירים סתומים בשל אבנית.. המלצה: לנקות את ראש המקלחת מאבנית (השרייה בחומץ), או להחליף בראש מקלחת חדש.. עלות משוערת: ₪50-₪300 (ליחידה)', '**ראש מקלחת (דוש) – לחץ נמוך או סתימה** — ראש המקלחת מפזר מים בצורה לא אחידה, זרימה חלשה, או חלק מהנחירים סתומים בשל אבנית.. המלצה: לנקות את ראש המקלחת מאבנית (השרייה בחומץ), או להחליף בראש מקלחת חדש.. עלות משוערת: ₪50-₪300 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**חיבור מכונת כביסה – ללא סיפון וללא ברז ניתוק** — נקודת חיבור מכונת הכביסה ללא סיפון (חיבור ישיר לביוב), ללא ברז ניתוק נפרד, או עם צנרת ניקוז לא מותאמת.. המלצה: להתקין סיפון תקני, ברז ניתוק נפרד (אנגל), ונקודת ניקוז בקוטר 50 מ"מ לפחות.. עלות משוערת: ₪300-₪800 (ליחידה)', '**חיבור מכונת כביסה – ללא סיפון וללא ברז ניתוק** — נקודת חיבור מכונת הכביסה ללא סיפון (חיבור ישיר לביוב), ללא ברז ניתוק נפרד, או עם צנרת ניקוז לא מותאמת.. המלצה: להתקין סיפון תקני, ברז ניתוק נפרד (אנגל), ונקודת ניקוז בקוטר 50 מ"מ לפחות.. עלות משוערת: ₪300-₪800 (ליחידה)', 'ת"י 1205 חלק 2 — חיבור מכונת כביסה חייב לכלול סיפון עם מחסום ריח, ברז ניתוק נפרד למים, וניקוז בקוטר מתאים.', 'ת"י 1205 חלק 2 — חיבור מכונת כביסה חייב לכלול סיפון עם מחסום ריח, ברז ניתוק נפרד למים, וניקוז בקוטר מתאים.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**חיבור מדיח כלים – ללא סיפון וללא מפסק** — נקודת חיבור מדיח הכלים ללא סיפון, ללא ברז ניתוק, או ללא לולאה עילית (high loop) בצנרת הניקוז.. המלצה: להתקין סיפון ולולאה עילית לצנרת הניקוז, להוסיף ברז ניתוק נפרד.. עלות משוערת: ₪250-₪600 (ליחידה)', '**חיבור מדיח כלים – ללא סיפון וללא מפסק** — נקודת חיבור מדיח הכלים ללא סיפון, ללא ברז ניתוק, או ללא לולאה עילית (high loop) בצנרת הניקוז.. המלצה: להתקין סיפון ולולאה עילית לצנרת הניקוז, להוסיף ברז ניתוק נפרד.. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 1205 חלק 2 — חיבור מדיח כלים חייב לכלול סיפון, ברז ניתוק, וצנרת ניקוז עם לולאה עילית למניעת זרימה חוזרת.', 'ת"י 1205 חלק 2 — חיבור מדיח כלים חייב לכלול סיפון, ברז ניתוק, וצנרת ניקוז עם לולאה עילית למניעת זרימה חוזרת.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**אסלה תלויה – מסגרת הרכבה (סטלז'') רופפת** — מסגרת ההרכבה של אסלה תלויה (concealed cistern frame) רופפת, גורמת לתנודות באסלה ולסיכון בטיחותי.. המלצה: לחזק את עיגון מסגרת ההרכבה לקיר ולרצפה, להדק את כל הברגים, ולוודא יציבות מלאה.. עלות משוערת: ₪400-₪1500 (ליחידה)', '**אסלה תלויה – מסגרת הרכבה (סטלז'') רופפת** — מסגרת ההרכבה של אסלה תלויה (concealed cistern frame) רופפת, גורמת לתנודות באסלה ולסיכון בטיחותי.. המלצה: לחזק את עיגון מסגרת ההרכבה לקיר ולרצפה, להדק את כל הברגים, ולוודא יציבות מלאה.. עלות משוערת: ₪400-₪1500 (ליחידה)', 'ת"י 1205 חלק 2 — מסגרת הרכבה לאסלה תלויה חייבת לשאת עומס מינימלי של 400 ק"ג ולהיות מעוגנת לרצפה ולקיר.', 'ת"י 1205 חלק 2 — מסגרת הרכבה לאסלה תלויה חייבת לשאת עומס מינימלי של 400 ק"ג ולהיות מעוגנת לרצפה ולקיר.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**כפתור הפעלה (לחצן) ניאגרה סמויה – לא תקין** — כפתור ההפעלה של ניאגרה סמויה (concealed cistern) לא עובד, תקוע, או אינו מפעיל את שני נפחי השטיפה (3/6 ליטר).. המלצה: להחליף את מנגנון ההפעלה הפנימי של הניאגרה, לכוונן את מוטות ההפעלה, ולבדוק תקינות שני מצבי השטיפה.. עלות משוערת: ₪200-₪700 (ליחידה)', '**כפתור הפעלה (לחצן) ניאגרה סמויה – לא תקין** — כפתור ההפעלה של ניאגרה סמויה (concealed cistern) לא עובד, תקוע, או אינו מפעיל את שני נפחי השטיפה (3/6 ליטר).. המלצה: להחליף את מנגנון ההפעלה הפנימי של הניאגרה, לכוונן את מוטות ההפעלה, ולבדוק תקינות שני מצבי השטיפה.. עלות משוערת: ₪200-₪700 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**התקנת כלי סניטרי בגובה לא תקני** — כיור, אסלה, או כלי סניטרי אחר מותקן בגובה שאינו עומד בדרישות הנגישות או התקן (גבוה/נמוך מדי).. המלצה: לפרק ולהתקין מחדש את הכלי הסניטרי בגובה התקני המתאים.. עלות משוערת: ₪300-₪1200 (ליחידה)', '**התקנת כלי סניטרי בגובה לא תקני** — כיור, אסלה, או כלי סניטרי אחר מותקן בגובה שאינו עומד בדרישות הנגישות או התקן (גבוה/נמוך מדי).. המלצה: לפרק ולהתקין מחדש את הכלי הסניטרי בגובה התקני המתאים.. עלות משוערת: ₪300-₪1200 (ליחידה)', 'ת"י 1205 חלק 2 — גובהות התקנה מומלצים: כיור רחצה – 80-85 ס"מ, אסלה – 40-42 ס"מ, כיור מטבח – 85-90 ס"מ (מידות מדף עליון).', 'ת"י 1205 חלק 2 — גובהות התקנה מומלצים: כיור רחצה – 80-85 ס"מ, אסלה – 40-42 ס"מ, כיור מטבח – 85-90 ס"מ (מידות מדף עליון).', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**סיליקון סניטרי פגום או מעופש סביב כלים סניטריים** — סיליקון סניטרי סביב כיור, אמבטיה, אסלה, או משטח עבודה שחור מעובש, סדוק, מתקלף, או חסר.. המלצה: להסיר את הסיליקון הישן בשלמותו, לנקות ולחטא את המשטח, ולמרוח סיליקון סניטרי חדש עמיד לעובש.. עלות משוערת: ₪100-₪350 (ליחידה)', '**סיליקון סניטרי פגום או מעופש סביב כלים סניטריים** — סיליקון סניטרי סביב כיור, אמבטיה, אסלה, או משטח עבודה שחור מעובש, סדוק, מתקלף, או חסר.. המלצה: להסיר את הסיליקון הישן בשלמותו, לנקות ולחטא את המשטח, ולמרוח סיליקון סניטרי חדש עמיד לעובש.. עלות משוערת: ₪100-₪350 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**ויסות טמפרטורה לקוי – מים רותחים מברז** — טמפרטורת המים החמים מהברז גבוהה מדי (מעל 50°C), מהווה סכנת כוויות, במיוחד לילדים ולקשישים.. המלצה: לכוונן את הטרמוסטט של דוד/בויילר, או להתקין מערבל תרמוסטטי (TMV) למניעת טמפרטורות מסוכנות.. עלות משוערת: ₪200-₪800 (ליחידה)', '**ויסות טמפרטורה לקוי – מים רותחים מברז** — טמפרטורת המים החמים מהברז גבוהה מדי (מעל 50°C), מהווה סכנת כוויות, במיוחד לילדים ולקשישים.. המלצה: לכוונן את הטרמוסטט של דוד/בויילר, או להתקין מערבל תרמוסטטי (TMV) למניעת טמפרטורות מסוכנות.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 1 — טמפרטורת מים חמים בנקודות שימוש לא תעלה על 50°C. יש להתקין מערבל תרמוסטטי (TMV) במידת הצורך.', 'ת"י 1205 חלק 1 — טמפרטורת מים חמים בנקודות שימוש לא תעלה על 50°C. יש להתקין מערבל תרמוסטטי (TMV) במידת הצורך.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כלים סניטריים', '**אסלה לא יציבה / רופפת** — אסלה שלא מחוברת יציב לרצפה — מתנדנדת בשימוש.. המלצה: חיזוק חיבור אסלה לרצפה, החלפת ברגי עיגון. עלות משוערת: ₪200-₪500 (ליחידה)', '**אסלה לא יציבה / רופפת** — אסלה שלא מחוברת יציב לרצפה — מתנדנדת בשימוש.. המלצה: חיזוק חיבור אסלה לרצפה, החלפת ברגי עיגון. עלות משוערת: ₪200-₪500 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — נזילת מים מהמסגרת** — חדירת מים דרך מסגרת החלון בזמן גשם או מבחן מים. הנזילה יכולה להופיע בפינות המסגרת, בחיבור לקיר, או דרך חורי הניקוז. גורמים נפוצים: איטום לקוי בין המסגרת לקיר, חוסר בסיליקון חיצוני, או חורי ניקוז חסומים.. המלצה: לבצע מבחן מים (זרנוק לחץ 2 אטמ'' למשך 15 דקות). לאתר מקור הנזילה — אם מחיבור לקיר: להסיר איטום ישן, למלא ביורתן ולאטום מחדש בסיליקון. אם מחורי ניקוז: לנקות ולוודא שפיכה חופשית.. עלות משוערת: ₪250-₪800 (ליחידה)', '**חלון אלומיניום — נזילת מים מהמסגרת** — חדירת מים דרך מסגרת החלון בזמן גשם או מבחן מים. הנזילה יכולה להופיע בפינות המסגרת, בחיבור לקיר, או דרך חורי הניקוז. גורמים נפוצים: איטום לקוי בין המסגרת לקיר, חוסר בסיליקון חיצוני, או חורי ניקוז חסומים.. המלצה: לבצע מבחן מים (זרנוק לחץ 2 אטמ'' למשך 15 דקות). לאתר מקור הנזילה — אם מחיבור לקיר: להסיר איטום ישן, למלא ביורתן ולאטום מחדש בסיליקון. אם מחורי ניקוז: לנקות ולוודא שפיכה חופשית.. עלות משוערת: ₪250-₪800 (ליחידה)', 'ת"י 1509 — חלון אלומיניום חייב לעמוד בדרישות אטימות למים בלחץ רוח של 300 פסקל לפחות (תלוי בקומה ובאזור גיאוגרפי)', 'ת"י 1509 — חלון אלומיניום חייב לעמוד בדרישות אטימות למים בלחץ רוח של 300 פסקל לפחות (תלוי בקומה ובאזור גיאוגרפי)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — חורי ניקוז חסומים או חסרים** — חורי הניקוז (דרנז''ים) בתחתית מסגרת החלון חסומים על ידי טיט, צבע או חומרי בנייה, או שלא נקדחו כלל במהלך ההתקנה. חורי ניקוז נדרשים להוצאת מים שמצטברים בתעלת המסגרת התחתונה.. המלצה: לנקות את חורי הניקוז הקיימים. אם חסרים — לקדוח חורי ניקוז חדשים בתחתית המסגרת בהתאם למפרט היצרן ולהתקין פלאפות.. עלות משוערת: ₪80-₪200 (ליחידה)', '**חלון אלומיניום — חורי ניקוז חסומים או חסרים** — חורי הניקוז (דרנז''ים) בתחתית מסגרת החלון חסומים על ידי טיט, צבע או חומרי בנייה, או שלא נקדחו כלל במהלך ההתקנה. חורי ניקוז נדרשים להוצאת מים שמצטברים בתעלת המסגרת התחתונה.. המלצה: לנקות את חורי הניקוז הקיימים. אם חסרים — לקדוח חורי ניקוז חדשים בתחתית המסגרת בהתאם למפרט היצרן ולהתקין פלאפות.. עלות משוערת: ₪80-₪200 (ליחידה)', 'ת"י 1509 — נדרשים לפחות 2 חורי ניקוז בכל מסגרת חלון, בקוטר מינימלי של 8 מ"מ, עם כיסויי ניקוז (פלאפות) תקינים', 'ת"י 1509 — נדרשים לפחות 2 חורי ניקוז בכל מסגרת חלון, בקוטר מינימלי של 8 מ"מ, עם כיסויי ניקוז (פלאפות) תקינים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — גומיות איטום (EPDM) בלויות או חסרות** — גומיות האיטום (EPDM) שמוטמעות בתעלות הפרופיל סביב כנף החלון בלויות, מתקלפות, מתכווצות או חסרות לחלוטין. מצב זה גורם לחדירת רוח, מים, אבק ורעש.. המלצה: להחליף את כל גומיות האיטום בגומיות מקוריות של יצרן הפרופיל (Klil/Shamir/AGS). יש לוודא התאמה מדויקת לתעלת הפרופיל.. עלות משוערת: ₪150-₪400 (ליחידה)', '**חלון אלומיניום — גומיות איטום (EPDM) בלויות או חסרות** — גומיות האיטום (EPDM) שמוטמעות בתעלות הפרופיל סביב כנף החלון בלויות, מתקלפות, מתכווצות או חסרות לחלוטין. מצב זה גורם לחדירת רוח, מים, אבק ורעש.. המלצה: להחליף את כל גומיות האיטום בגומיות מקוריות של יצרן הפרופיל (Klil/Shamir/AGS). יש לוודא התאמה מדויקת לתעלת הפרופיל.. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1509 — חלון חייב לכלול מערכת איטום כפולה (פנימית וחיצונית) עם גומיות EPDM העומדות בתקן אריכות חיים', 'ת"י 1509 — חלון חייב לכלול מערכת איטום כפולה (פנימית וחיצונית) עם גומיות EPDM העומדות בתקן אריכות חיים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון הזזה — גלגלות תחתונות שחוקות** — גלגלות ההזזה (רולרים) בתחתית כנף חלון ההזזה שחוקות, שבורות או יוצאות ממסלולן. החלון נגרר בכבדות, קופץ מהמסילה, או לא נסגר עד הסוף.. המלצה: להחליף את הגלגלות בגלגלות מקוריות תואמות לסוג הפרופיל. לנקות את מסילת ההזזה התחתונה ולבדוק יישור.. עלות משוערת: ₪200-₪500 (ליחידה)', '**חלון הזזה — גלגלות תחתונות שחוקות** — גלגלות ההזזה (רולרים) בתחתית כנף חלון ההזזה שחוקות, שבורות או יוצאות ממסלולן. החלון נגרר בכבדות, קופץ מהמסילה, או לא נסגר עד הסוף.. המלצה: להחליף את הגלגלות בגלגלות מקוריות תואמות לסוג הפרופיל. לנקות את מסילת ההזזה התחתונה ולבדוק יישור.. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 1509 — כנף חלון הזזה חייבת לנוע בחופשיות ולהגיע לנעילה מלאה ללא מאמץ חריג', 'ת"י 1509 — כנף חלון הזזה חייבת לנוע בחופשיות ולהגיע לנעילה מלאה ללא מאמץ חריג', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון הזזה — מסילה תחתונה פגומה או מעוותת** — מסילת ההזזה התחתונה מעוותת, שקועה בטיח, מלוכלכת בחומרי בנייה, או שבורה. החלון לא מחליק כראוי ולא מגיע לסגירה מלאה.. המלצה: לנקות את המסילה מחומרי בנייה. אם מעוותת — להחליף את פרופיל המסילה. לבדוק ולתקן גובה המסילה ביחס לרצפה.. עלות משוערת: ₪200-₪600 (ליחידה)', '**חלון הזזה — מסילה תחתונה פגומה או מעוותת** — מסילת ההזזה התחתונה מעוותת, שקועה בטיח, מלוכלכת בחומרי בנייה, או שבורה. החלון לא מחליק כראוי ולא מגיע לסגירה מלאה.. המלצה: לנקות את המסילה מחומרי בנייה. אם מעוותת — להחליף את פרופיל המסילה. לבדוק ולתקן גובה המסילה ביחס לרצפה.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1509 — מסילת ההזזה חייבת להיות ישרה, חלקה, ונקייה מחסימות לאורך כל המסלול', 'ת"י 1509 — מסילת ההזזה חייבת להיות ישרה, חלקה, ונקייה מחסימות לאורך כל המסלול', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון ציר (קייסמנט) — ציר עליון/תחתון רופף או שבור** — צירי חלון הציר (קייסמנט) רופפים, חורקים, או שבורים. הכנף צונחת, לא נסגרת בצורה אחידה, או נשארת פתוחה שלא כרצון.. המלצה: להדק את ברגי הצירים. אם הצירים שחוקים או שבורים — להחליף בצירים מקוריים תואמי פרופיל. לכוונן את הכנף לאחר ההחלפה.. עלות משוערת: ₪200-₪600 (ליחידה)', '**חלון ציר (קייסמנט) — ציר עליון/תחתון רופף או שבור** — צירי חלון הציר (קייסמנט) רופפים, חורקים, או שבורים. הכנף צונחת, לא נסגרת בצורה אחידה, או נשארת פתוחה שלא כרצון.. המלצה: להדק את ברגי הצירים. אם הצירים שחוקים או שבורים — להחליף בצירים מקוריים תואמי פרופיל. לכוונן את הכנף לאחר ההחלפה.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1509 — צירים חייבים לשאת את משקל הכנף ללא שקיעה ולאפשר פתיחה/סגירה חלקה לאורך חיי המוצר', 'ת"י 1509 — צירים חייבים לשאת את משקל הכנף ללא שקיעה ולאפשר פתיחה/סגירה חלקה לאורך חיי המוצר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון דריי-קיפ — מנגנון פתיחה כפולה תקול** — מנגנון הפתיחה הכפולה (tilt & turn / דריי-קיפ) אינו פועל כראוי — החלון לא עובר בין מצב הטיה לפתיחה צירית, ידית תקועה, או הכנף ננעלת במצב ביניים מסוכן.. המלצה: לכוונן את נקודות הנעילה (espagnolette) של המנגנון. אם המנגנון פגום — להחליף מנגנון דריי-קיפ שלם תואם ליצרן הפרופיל.. עלות משוערת: ₪400-₪1200 (ליחידה)', '**חלון דריי-קיפ — מנגנון פתיחה כפולה תקול** — מנגנון הפתיחה הכפולה (tilt & turn / דריי-קיפ) אינו פועל כראוי — החלון לא עובר בין מצב הטיה לפתיחה צירית, ידית תקועה, או הכנף ננעלת במצב ביניים מסוכן.. המלצה: לכוונן את נקודות הנעילה (espagnolette) של המנגנון. אם המנגנון פגום — להחליף מנגנון דריי-קיפ שלם תואם ליצרן הפרופיל.. עלות משוערת: ₪400-₪1200 (ליחידה)', 'ת"י 1509 — מנגנון פתיחה כפולה חייב לעבור בין שלושת המצבים (סגור, הטיה, פתיחה) בצורה חלקה ובטוחה', 'ת"י 1509 — מנגנון פתיחה כפולה חייב לעבור בין שלושת המצבים (סגור, הטיה, פתיחה) בצורה חלקה ובטוחה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — חוסר גשר תרמי (thermal break)** — הותקן פרופיל אלומיניום ללא גשר תרמי (פוליאמיד) במקום שנדרש פרופיל תרמי. ללא גשר תרמי נוצרת עיבוי (קונדנסציה) על הפרופיל בחורף וישנה אובדן אנרגיה משמעותי.. המלצה: להחליף את החלון בחלון עם פרופיל בעל גשר תרמי (thermal break). ליקוי זה דורש החלפה מלאה של המסגרת והכנפות.. עלות משוערת: ₪1500-₪4000 (למ"ר)', '**חלון אלומיניום — חוסר גשר תרמי (thermal break)** — הותקן פרופיל אלומיניום ללא גשר תרמי (פוליאמיד) במקום שנדרש פרופיל תרמי. ללא גשר תרמי נוצרת עיבוי (קונדנסציה) על הפרופיל בחורף וישנה אובדן אנרגיה משמעותי.. המלצה: להחליף את החלון בחלון עם פרופיל בעל גשר תרמי (thermal break). ליקוי זה דורש החלפה מלאה של המסגרת והכנפות.. עלות משוערת: ₪1500-₪4000 (למ"ר)', 'ת"י 1045 — תקן בידוד תרמי במבנים מחייב ערך U מרבי לחלונות — פרופיל עם גשר תרמי נדרש באזורי אקלים B ו-C', 'ת"י 1045 — תקן בידוד תרמי במבנים מחייב ערך U מרבי לחלונות — פרופיל עם גשר תרמי נדרש באזורי אקלים B ו-C', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — איטום חיצוני לקוי בין מסגרת לקיר** — האיטום החיצוני בין מסגרת האלומיניום לקיר (טיח/שיש) חסר, סדוק, או לא רציף. הסיליקון מתקלף, מצהיב, או לא מכסה את כל המפגש. גורם לחדירת מים ורוח.. המלצה: להסיר איטום ישן, לנקות את המשטחים, למלא ביורתן גמיש ולאטום מחדש בסיליקון חיצוני UV-resistant מתאים לאלומיניום.. עלות משוערת: ₪150-₪500 (ליחידה)', '**חלון אלומיניום — איטום חיצוני לקוי בין מסגרת לקיר** — האיטום החיצוני בין מסגרת האלומיניום לקיר (טיח/שיש) חסר, סדוק, או לא רציף. הסיליקון מתקלף, מצהיב, או לא מכסה את כל המפגש. גורם לחדירת מים ורוח.. המלצה: להסיר איטום ישן, לנקות את המשטחים, למלא ביורתן גמיש ולאטום מחדש בסיליקון חיצוני UV-resistant מתאים לאלומיניום.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1509 — נדרש איטום רציף ואלסטי בכל היקף החלון בין המסגרת למשקוף/אדן', 'ת"י 1509 — נדרש איטום רציף ואלסטי בכל היקף החלון בין המסגרת למשקוף/אדן', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — רשת יתושים קרועה או חסרה** — רשת היתושים קרועה, מנותקת מהמסגרת, או לא סופקה כלל. במפרט הדירה נדרשת רשת יתושים בכל חלון.. המלצה: להתקין/להחליף רשת יתושים תואמת — רשת הזזה, גלילה, או קבועה בהתאם לסוג החלון.. עלות משוערת: ₪150-₪450 (ליחידה)', '**חלון אלומיניום — רשת יתושים קרועה או חסרה** — רשת היתושים קרועה, מנותקת מהמסגרת, או לא סופקה כלל. במפרט הדירה נדרשת רשת יתושים בכל חלון.. המלצה: להתקין/להחליף רשת יתושים תואמת — רשת הזזה, גלילה, או קבועה בהתאם לסוג החלון.. עלות משוערת: ₪150-₪450 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — מסגרת מעוותת או לא מפולסת** — מסגרת החלון לא מפולסת (לא במאוזן/מאונך), מעוותת, או מפותלת. הכנף לא נסגרת באחידות, יש פער לא אחיד בין הכנף למסגרת, נגרמים בעיות איטום ונעילה.. המלצה: לפרק את החלון, ליישר את המסגרת בפילוס מדויק, לעגן מחדש ולאטום. במקרים חמורים — להחליף מסגרת.. עלות משוערת: ₪400-₪1500 (ליחידה)', '**חלון אלומיניום — מסגרת מעוותת או לא מפולסת** — מסגרת החלון לא מפולסת (לא במאוזן/מאונך), מעוותת, או מפותלת. הכנף לא נסגרת באחידות, יש פער לא אחיד בין הכנף למסגרת, נגרמים בעיות איטום ונעילה.. המלצה: לפרק את החלון, ליישר את המסגרת בפילוס מדויק, לעגן מחדש ולאטום. במקרים חמורים — להחליף מסגרת.. עלות משוערת: ₪400-₪1500 (ליחידה)', 'ת"י 1509 — סטייה מרבית מאנכיות ואופקיות: 2 מ"מ למטר אורך, עד מקסימום 3 מ"מ', 'ת"י 1509 — סטייה מרבית מאנכיות ואופקיות: 2 מ"מ למטר אורך, עד מקסימום 3 מ"מ', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — שריטות או נזק לפרופיל** — שריטות עמוקות, מכות, או נזק לציפוי האלקטרוסטטי (אנודייז או צביעה) של פרופיל האלומיניום. נגרם בדרך כלל במהלך עבודות בנייה או הובלה.. המלצה: שריטות שטחיות — לטפל בצבע תיקון מקורי מהיצרן. שריטות עמוקות/נרחבות — להחליף את הפרופיל הפגום.. עלות משוערת: ₪100-₪500 (ליחידה)', '**חלון אלומיניום — שריטות או נזק לפרופיל** — שריטות עמוקות, מכות, או נזק לציפוי האלקטרוסטטי (אנודייז או צביעה) של פרופיל האלומיניום. נגרם בדרך כלל במהלך עבודות בנייה או הובלה.. המלצה: שריטות שטחיות — לטפל בצבע תיקון מקורי מהיצרן. שריטות עמוקות/נרחבות — להחליף את הפרופיל הפגום.. עלות משוערת: ₪100-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — הרכבה ללא עיגון תקני לקיר** — מסגרת החלון מעוגנת לקיר בצורה לא תקנית — רק בקצף פוליאורתן ללא דיבלים, עם מספר לא מספיק של נקודות עיגון, או עם מרווחים גדולים מדי בין נקודות העיגון.. המלצה: להוסיף נקודות עיגון מכאניות (פישר + בורג נירוסטה) בהתאם לתקן. לא להסתפק בקצף בלבד.. עלות משוערת: ₪200-₪600 (ליחידה)', '**חלון אלומיניום — הרכבה ללא עיגון תקני לקיר** — מסגרת החלון מעוגנת לקיר בצורה לא תקנית — רק בקצף פוליאורתן ללא דיבלים, עם מספר לא מספיק של נקודות עיגון, או עם מרווחים גדולים מדי בין נקודות העיגון.. המלצה: להוסיף נקודות עיגון מכאניות (פישר + בורג נירוסטה) בהתאם לתקן. לא להסתפק בקצף בלבד.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1509 — נדרשות נקודות עיגון מכאניות (דיבלים/ברגי בטון) כל 60 ס"מ לפחות, ולא יותר מ-15 ס"מ מכל פינה', 'ת"י 1509 — נדרשות נקודות עיגון מכאניות (דיבלים/ברגי בטון) כל 60 ס"מ לפחות, ולא יותר מ-15 ס"מ מכל פינה', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — חדירת אוויר (רוח) חריגה** — חדירת אוויר חריגה דרך החלון במצב סגור — מורגשת רוח, שריקת רוח, או נכנס אבק. הגורם: גומיות לא תקינות, נעילה חלקית, מסגרת לא מיושרת.. המלצה: לבדוק ולהחליף גומיות איטום. לכוונן נקודות נעילה להידוק מלא. לבדוק יישור מסגרת. לבצע בדיקת blower door אם נדרש.. עלות משוערת: ₪200-₪600 (ליחידה)', '**חלון אלומיניום — חדירת אוויר (רוח) חריגה** — חדירת אוויר חריגה דרך החלון במצב סגור — מורגשת רוח, שריקת רוח, או נכנס אבק. הגורם: גומיות לא תקינות, נעילה חלקית, מסגרת לא מיושרת.. המלצה: לבדוק ולהחליף גומיות איטום. לכוונן נקודות נעילה להידוק מלא. לבדוק יישור מסגרת. לבצע בדיקת blower door אם נדרש.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1509 — חדירת אוויר מרבית: סיווג A2 לפחות (6.75 מ"ק/שעה/מ"ר בלחץ 100 פסקל)', 'ת"י 1509 — חדירת אוויר מרבית: סיווג A2 לפחות (6.75 מ"ק/שעה/מ"ר בלחץ 100 פסקל)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — אדן שיש חיצוני ללא שיפוע** — אדן השיש/אבן החיצוני של החלון ללא שיפוע כלפי חוץ, או עם שיפוע הפוך — מים מצטברים על האדן ונכנסים פנימה במקום לנקז החוצה.. המלצה: להתקין מחדש את אדן השיש בשיפוע של 3-5% כלפי חוץ. לוודא טפטפת בחזית האדן ואיטום למסגרת.. עלות משוערת: ₪300-₪800 (ליחידה)', '**חלון אלומיניום — אדן שיש חיצוני ללא שיפוע** — אדן השיש/אבן החיצוני של החלון ללא שיפוע כלפי חוץ, או עם שיפוע הפוך — מים מצטברים על האדן ונכנסים פנימה במקום לנקז החוצה.. המלצה: להתקין מחדש את אדן השיש בשיפוע של 3-5% כלפי חוץ. לוודא טפטפת בחזית האדן ואיטום למסגרת.. עלות משוערת: ₪300-₪800 (ליחידה)', 'ת"י 1509 — אדן חיצוני חייב להיות משופע כלפי חוץ עם טפטפת (drip edge) למניעת זרימת מים לקיר', 'ת"י 1509 — אדן חיצוני חייב להיות משופע כלפי חוץ עם טפטפת (drip edge) למניעת זרימת מים לקיר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — צבע פרופיל לא תואם למפרט** — צבע הפרופיל (RAL) לא תואם למפרט הפרויקט — גוון שונה, צבע מתקלף, ציפוי לא אחיד, או הבדלי גוון בין חלונות שונים באותה דירה.. המלצה: אם הצבע לא תואם למפרט — להחליף את הפרופילים הפגומים. אם ציפוי מתקלף — תביעת אחריות מיצרן הפרופיל.. עלות משוערת: ₪500-₪2000 (ליחידה)', '**חלון אלומיניום — צבע פרופיל לא תואם למפרט** — צבע הפרופיל (RAL) לא תואם למפרט הפרויקט — גוון שונה, צבע מתקלף, ציפוי לא אחיד, או הבדלי גוון בין חלונות שונים באותה דירה.. המלצה: אם הצבע לא תואם למפרט — להחליף את הפרופילים הפגומים. אם ציפוי מתקלף — תביעת אחריות מיצרן הפרופיל.. עלות משוערת: ₪500-₪2000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון אלומיניום — עיבוי (קונדנסציה) על הפרופיל** — עיבוי מים (קונדנסציה) נוצר על פרופיל האלומיניום בחורף, בעיקר בפרופיל ללא גשר תרמי. המים נוזלים לאדן ולקיר וגורמים לעובש ולנזק.. המלצה: פתרון מלא: החלפת חלון לפרופיל עם גשר תרמי. פתרון חלקי: שיפור אוורור החדר, התקנת מפוח אוויר.. עלות משוערת: ₪1500-₪4000 (למ"ר)', '**חלון אלומיניום — עיבוי (קונדנסציה) על הפרופיל** — עיבוי מים (קונדנסציה) נוצר על פרופיל האלומיניום בחורף, בעיקר בפרופיל ללא גשר תרמי. המים נוזלים לאדן ולקיר וגורמים לעובש ולנזק.. המלצה: פתרון מלא: החלפת חלון לפרופיל עם גשר תרמי. פתרון חלקי: שיפור אוורור החדר, התקנת מפוח אוויר.. עלות משוערת: ₪1500-₪4000 (למ"ר)', 'ת"י 1045 — מעטפת הבניין, כולל חלונות, חייבת למנוע עיבוי על משטחים פנימיים בתנאי שימוש רגילים', 'ת"י 1045 — מעטפת הבניין, כולל חלונות, חייבת למנוע עיבוי על משטחים פנימיים בתנאי שימוש רגילים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — חלונות', '**חלון לא אוטם — חדירת אוויר/מים** — חלון שלא אוטם כראוי — חדירת אוויר, מים או אבק.. המלצה: החלפת רצועות אטימה, תיקון סיליקון, כוונון. עלות משוערת: ₪100-₪350 (ליחידה)', '**חלון לא אוטם — חדירת אוויר/מים** — חלון שלא אוטם כראוי — חדירת אוויר, מים או אבק.. המלצה: החלפת רצועות אטימה, תיקון סיליקון, כוונון. עלות משוערת: ₪100-₪350 (ליחידה)', 'ת"י 23 — חלונות חייבים לעמוד בתקן אטימות למים ואוויר', 'ת"י 23 — חלונות חייבים לעמוד בתקן אטימות למים ואוויר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת מרפסת אלומיניום — סף תחתון גבוה מדי** — סף דלת המרפסת בולט מעל פני הרצפה ביותר מ-20 מ"מ, מהווה מכשול מעידה ואינו נגיש לנכים ולעגלות.. המלצה: להחליף את הסף בסף נמוך/שטוח תואם נגישות. אם לא ניתן — להתקין רמפה משופעת בשני צדי הסף.. עלות משוערת: ₪300-₪900 (ליחידה)', '**דלת מרפסת אלומיניום — סף תחתון גבוה מדי** — סף דלת המרפסת בולט מעל פני הרצפה ביותר מ-20 מ"מ, מהווה מכשול מעידה ואינו נגיש לנכים ולעגלות.. המלצה: להחליף את הסף בסף נמוך/שטוח תואם נגישות. אם לא ניתן — להתקין רמפה משופעת בשני צדי הסף.. עלות משוערת: ₪300-₪900 (ליחידה)', 'ת"י 1918 — דרישות נגישות — סף דלת לא יעלה על 20 מ"מ, ורצוי סף שטוח/משופע', 'ת"י 1918 — דרישות נגישות — סף דלת לא יעלה על 20 מ"מ, ורצוי סף שטוח/משופע', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת מרפסת הזזה — גלילה כבדה ולא חלקה** — דלת ההזזה למרפסת נגררת בכבדות, דורשת כוח רב לפתיחה/סגירה, או נתקעת באמצע המסלול. נגרם מגלגלות שחוקות, מסילה מלוכלכת, או כנף לא מכוונת.. המלצה: לנקות מסילות, לשמן גלגלות. להחליף גלגלות שחוקות. לכוונן גובה כנף ביחס למסילה.. עלות משוערת: ₪250-₪700 (ליחידה)', '**דלת מרפסת הזזה — גלילה כבדה ולא חלקה** — דלת ההזזה למרפסת נגררת בכבדות, דורשת כוח רב לפתיחה/סגירה, או נתקעת באמצע המסלול. נגרם מגלגלות שחוקות, מסילה מלוכלכת, או כנף לא מכוונת.. המלצה: לנקות מסילות, לשמן גלגלות. להחליף גלגלות שחוקות. לכוונן גובה כנף ביחס למסילה.. עלות משוערת: ₪250-₪700 (ליחידה)', 'ת"י 1509 — דלת הזזה חייבת להיפתח בכוח שאינו עולה על 50 ניוטון (כ-5 ק"ג)', 'ת"י 1509 — דלת הזזה חייבת להיפתח בכוח שאינו עולה על 50 ניוטון (כ-5 ק"ג)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אלומיניום — דלתות', '**דלת מרפסת הזזה — נעילה רב-נקודתית לא תקינה** — מנגנון הנעילה הרב-נקודתי של דלת המרפסת לא פועל כראוי — חלק מנקודות הנעילה לא ננעלות, הידית לא מסתובבת עד הסוף, או שהנעילה לא אטומה.. המלצה: לכוונן את נקודות הנעילה והנגדים. לשמן את מוטות הנעילה. אם המנגנון פגום — להחליף את מערכת הנעילה.. עלות משוערת: ₪350-₪1000 (ליחידה)', '**דלת מרפסת הזזה — נעילה רב-נקודתית לא תקינה** — מנגנון הנעילה הרב-נקודתי של דלת המרפסת לא פועל כראוי — חלק מנקודות הנעילה לא ננעלות, הידית לא מסתובבת עד הסוף, או שהנעילה לא אטומה.. המלצה: לכוונן את נקודות הנעילה והנגדים. לשמן את מוטות הנעילה. אם המנגנון פגום — להחליף את מערכת הנעילה.. עלות משוערת: ₪350-₪1000 (ליחידה)', 'ת"י 1509 — דלת חייבת להינעל בנעילה רב-נקודתית המבטיחה איטום ואבטחה בכל נקודות המגע', 'ת"י 1509 — דלת חייבת להינעל בנעילה רב-נקודתית המבטיחה איטום ואבטחה בכל נקודות המגע', true, 'medium');
